    locationMessage = `Location ID is required for item ${i + 1} in Location Transfer`
    break;
  }
}

const hasQuantity = subformData.some((line) => {
  if (!line.temp_qty_data) return false;
  try {
    const parsed = JSON.parse(line.temp_qty_data);
    return Array.isArray(parsed) && parsed.some(
      (entry) => entry.sm_quantity && parseFloat(entry.sm_quantity) > 0
    );
  } catch (e) {
    return false;
